import { Phone,Forklift, Radio, DollarSign, CheckSquare, File } from 'lucide-react';
// Données du graphique à barres
export const chartData = [
  { name: 'Sun', value: 200 },
  { name: 'Mon', value: 180 },
  { name: 'Tue', value: 320 },
  { name: 'Wed', value: 50 },
  { name: 'Thu', value: 510 },
  { name: 'Fri', value: 190 },
  { name: 'Sat', value: 490 },
];

// Données des mises à jour du jour
export const todayUpdates = [
  { name: 'VOCALCOM', value: 13, icon: <Phone className="text-gray-500" size={20} /> },
  { name: 'RBS', value: 16, icon: <Radio className="text-gray-500" size={20} /> },
  { name: 'UTIBA_2TMV', value: 20, icon: <DollarSign className="text-gray-500" size={20} /> },
  { name: 'LYNX', value: 26, icon: <CheckSquare className="text-gray-500" size={20} /> },
  { name: 'LOGICAR', value: 45, icon: <Forklift className="text-gray-500" size={20} /> },
  { name: 'SIMS', value: 16, icon: <File className="text-gray-500" size={20} /> },
];

// Données du graphique linéaire
export const lineData = [
  { name: "Jan", value: 200 },
  { name: "Feb", value: 400 },
  { name: "Mar", value: 300 },
  { name: "Apr", value: 600 },
  { name: "May", value: 400 },
  { name: "Jun", value: 500 },
];
